import React, { useState, useEffect } from 'react';
import './Projects.css';

interface Project {
  _id?: string;
  title: string;
  description: string;
  technologies: string[];
  liveUrl: string;
  githubUrl: string;
  imageUrl: string;
  featured: boolean;
}

const Projects: React.FC = () => {
  const [projects, setProjects] = useState<Project[]>([
    {
      title: 'QUICKART',
      description: 'Developed a full-featured e-commerce web application using Django. Implemented features such as login/logout, signup, order placing with existing or new addresses, order tracking, and a beautiful user interface. Classified products into different categories for easy navigation and browsing.',
      technologies: ['HTML', 'CSS', 'JavaScript', 'Django'],
      liveUrl: 'https://example-quickart.com',
      githubUrl: 'https://github.com/username/quickart',
      imageUrl: '/project1.jpg',
      featured: true
    }
  ]);

  const [filter, setFilter] = useState<string>('all');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);

  useEffect(() => {
    const fetchProjects = async () => {
      try {
        const response = await fetch('/api/projects');
        if (response.ok) {
          const data = await response.json();
          if (data && data.length > 0) {
            setProjects(data);
          }
        }
      } catch (error) {
        console.log('Using default projects, API not available');
      }
    };

    fetchProjects();
  }, []);

  const filteredProjects = filter === 'all' 
    ? projects 
    : projects.filter(project => project.featured);

  const handleImageError = (e: React.SyntheticEvent<HTMLImageElement>) => {
    const target = e.target as HTMLImageElement;
    target.src = 'data:image/svg+xml;base64,';
  };

  return (
    <div className="projects">
      <div className="container">
        <h1 className="page-title">My Projects</h1>

        <div className="filter-section">
          <button 
            className={`filter-btn ${filter === 'all' ? 'active' : ''}`}
            onClick={() => setFilter('all')}
          >
            All Projects
          </button>
          <button 
            className={`filter-btn ${filter === 'featured' ? 'active' : ''}`}
            onClick={() => setFilter('featured')}
          >
            Featured Only
          </button>
        </div>

        <div className="projects-grid">
          {filteredProjects.map((project, index) => (
            <div key={project._id || index} className="project-card">
              <div className="project-image" onClick={() => setSelectedProject(project)}>
                <img 
                  src={project.imageUrl} 
                  alt={project.title}
                  onError={handleImageError}
                  style={{ cursor: 'pointer' }}
                />
                {project.featured && (
                  <span className="featured-badge">Featured</span>
                )}
              </div>

              <div className="project-content">
                <h3>{project.title}</h3>
                <p className="project-description">{project.description}</p>

                <div className="project-technologies">
                  {project.technologies.map((tech, techIndex) => (
                    <span key={techIndex} className="tech-tag">{tech}</span>
                  ))}
                </div>

                <div className="project-links">
                  <a 
                    href={project.liveUrl} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="btn btn-primary"
                  >
                    Live Demo
                  </a>
                  <a 
                    href={project.githubUrl} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="btn btn-secondary"
                  >
                    View Code
                  </a>
                </div>
              </div>
            </div>
          ))}
        </div>

        {filteredProjects.length === 0 && (
          <div className="no-projects">
            <p>No projects found for the selected filter.</p>
          </div>
        )}

        {/* Project Details Modal */}
        {selectedProject && (
          <div className="project-modal" onClick={() => setSelectedProject(null)}>
            <div className="modal-content" onClick={(e) => e.stopPropagation()}>
              <div className="modal-header">
                <h2>{selectedProject.title}</h2>
                <button className="close-btn" onClick={() => setSelectedProject(null)}>×</button>
              </div>
              <div className="modal-body">
                <div className="modal-image">
                  <img 
                    src={selectedProject.imageUrl} 
                    alt={selectedProject.title}
                    onError={handleImageError}
                  />
                </div>
                <div className="modal-details">
                  <p className="modal-description">{selectedProject.description}</p>
                  <div className="modal-technologies">
                    <h4>Technologies Used:</h4>
                    <div className="tech-tags">
                      {selectedProject.technologies.map((tech, index) => (
                        <span key={index} className="tech-tag">{tech}</span>
                      ))}
                    </div>
                  </div>
                  <div className="modal-links">
                    <a 
                      href={selectedProject.liveUrl} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="btn btn-primary"
                    >
                      Live Demo
                    </a>
                    <a 
                      href={selectedProject.githubUrl} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="btn btn-secondary"
                    >
                      View Code
                    </a>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Projects;
